            read_text_file,
            write_text_file,
            export_backup,
            request_import_backup,
            has_pending_import,
            cancel_pending_import,
            append_log,
            get_log_path,
            eval_dice,
            generate_illustration,
            start_export,
            resume_export,
            get_export_status,
            cancel_export,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

